    private static SoundEvent reference(String path) {
        SoundEvent keyed = SoundEvent.variableRange(ResourceKey.minecraft(path));
        dev.wyck.keys.KeyChains.SOUND_EVENTS.append(keyed);
        return keyed;
    }

    private SoundEvents() {
        throw new UnsupportedOperationException("Not intended for instantiation");
    }
